class SlidingWindowContext:
    def __init__(self, max_tokens: int = 32000, model="gpt-4"):
        self.max_tokens = max_tokens
        self.enc = tiktoken.encoding_for_model(model)
        self.messages = []

    def add(self, role: str, content: str):
        self.messages.append({"role": role, "content": content})
        self._evict()

    def _evict(self):
        """Drop oldest messages until under budget."""
        # Keep system prompt always
        budget = self.max_tokens
        for m in reversed(self.messages):
            budget -= len(self.enc.encode(m['content']))
            if budget < 0:
                # Drop from the front (after system prompt)
                keep = self.messages[:1]  # system prompt
                for m in self.messages[1:]:
                    keep.append(m)
                    if sum(len(self.enc.encode(x['content'])) for x in keep) > self.max_tokens:
                        keep.pop()
                        break
                # Summarize dropped messages
                dropped = self.messages[len(keep):]
                if dropped:
                    summary = self._summarize(dropped)
                    keep.append({"role": "system", "content": f"[History summary]: {summary}"})
                self.messages = keep
                return

    def _summarize(self, messages: list) -> str:
        # ponytail: this would call an LLM; stub for illustration
        return f"{len(messages)} previous messages summarized."

    def get_context(self) -> list:
        return self.messages
